import { SVGModes } from "geometry-object";

export type BaseSVGProps = {
  geoId: string;
  mode: SVGModes;
  hoverable?: boolean;
  isHighlight: boolean;
  style?: React.CSSProperties;
  miniScale: boolean;
};

export interface BaseSVGState {
  isActive: boolean;
  css: string;
  isPinned?: boolean;
}

export enum AspectRatio {
  Portrait = "portrait",
  Landscape = "landscape",
  Square = "square",
}
